INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e3075ebd-2807-4c04-be9a-7b408292f1f3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Physics Optimization: Rigidbody, Colliders, and Triggers$escape$,
  $escape$Unity's physics engine can be a powerful tool for creating realistic gameplay, but it can also be a performance bottleneck if not used efficiently. Rigidbody components should be used sparingly, as they can be computationally expensive. Colliders, on the other hand, can be used to detect collisions without the overhead of a Rigidbody. Triggers can be used to detect overlaps without generating collision responses. Physics layers can be used to filter collisions and improve performance. By carefully considering the use of these components, developers can create engaging and realistic physics-based gameplay while minimizing performance implications.$escape$,
  $escape$using UnityEngine;
public class PhysicsExample : MonoBehaviour {
    void OnTriggerEnter(Collider other) {
        // Handle trigger event
    }
}$escape$,
