INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cf84f58a-7e08-45e3-bd99-abb560f737fe',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Asset Pipeline Optimization — Importing Models and Textures Efficiently$escape$,
  $escape$Unity's Asset Pipeline is crucial for efficient game development. When importing models and textures, using the `ModelImporter` and `TextureImporter` classes can help optimize assets. The `LODGroup` component allows for Level of Detail (LOD) optimization, reducing polygon counts for distant objects. To further optimize, use the `AssetPostprocessor` class to automate tasks such as texture compression and model simplification. This can significantly reduce build times and improve game performance.$escape$,
  $escape$using UnityEditor;
using UnityEngine;
public class AssetOptimizer : AssetPostprocessor {
    void OnPostprocessModel(ModelImporter importer) {
        importer.useFileScale = true;
    }
}$escape$,
  $escape$csharp$escape$,
