INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0381c625-fbc0-47a2-8e3b-7b317c761122',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Audio Optimization — Positional Audio with AudioSources$escape$,
  $escape$Unity's AudioSource component allows for positional audio, which simulates the way sound behaves in the real world. To achieve this, set the AudioSource's spatialize property to true and adjust the spatialBlend value to control the amount of spatialization. Additionally, use the AudioListener component to simulate the player's ears. For music and SFX, consider using separate AudioMixer groups to control volume and compression. The Adaptive Audio Limiter in Unity's Audio Mixer can help prevent audio clipping.$escape$,
  $escape$using UnityEngine; public class PositionalAudio : MonoBehaviour { private AudioSource audioSource; void Start() { audioSource = GetComponent<AudioSource>(); audioSource.spatialize = true; audioSource.spatialBlend = 1.0f; } }$escape$,
  $escape$csharp$escape$,
