INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2e989fef-1cef-4a34-8c43-4fdf1070ec36',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity Input Handling — Simplifying Controller Support with Input Actions$escape$,
  $escape$Unity's Input System package provides a robust way to handle input from various devices. By using Input Actions, you can create a single input abstraction that works across keyboards, mice, gamepads, and touchscreens. This allows for more flexibility and easier maintenance of your input handling code. To get started, create a new Input Actions asset and define your action maps. You can then use the InputAction class to read input values and perform actions. For example, you can use the ReadValue method to get the current value of an action, or the PerformInteractiveRebinding method to rebind an action at runtime.$escape$,
  $escape$using UnityEngine.InputSystem;

public class PlayerController : MonoBehaviour
{
    private PlayerControls controls;

    private void Awake()
    {
        controls = new PlayerControls();
        controls.Gameplay.Move.performed += ctx => Move(ctx.ReadValue<Vector2>());
    }
}$escape$,
  $escape$csharp$escape$,
