INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f1061023-947d-4a88-b3cc-fae57c7528eb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Unity: Leveraging Bevy's ECS for Efficient Game Development$escape$,
  $escape$Bevy, a Rust-powered game engine, adopts Entity-Component-System (ECS) architecture. In Unity, you can integrate Bevy as a plugin. This allows you to leverage Bevy's ECS for building efficient game systems. A key concept in Bevy is the entity, which represents a game object. Components, attached to entities, contain game-specific data. Systems, responsible for updating and manipulating components, are the core of Bevy's ECS. Bevy's ECS enables data-driven development, separating game logic from the engine. This approach facilitates easier maintenance and updates.$escape$,
  NULL,
  NULL,
